input.command:
kubectl patch statefulset es-cluster -n elasticsearch --type strategic -p '{
  "spec": {
    "template": {
      "spec": {
        "initContainers": [
          {
            "name": "fix-permissions",
            "image": "busybox:1.35",
            "command": ["sh", "-c", "chown -R 1000:1000 /usr/share/elasticsearch/data"],
            "volumeMounts": [
              {"mountPath": "/usr/share/elasticsearch/data", "name": "data"}
            ]
          },
          {
            "name": "keystore-setup",
            "image": "docker.elastic.co/elasticsearch/elasticsearch:8.11.1",
            "command": [
              "bash", "-c",
              "elasticsearch-keystore create 2>/dev/null || true; elasticsearch-keystore add -xf s3.client.default.access_key < /mnt/secure-settings/s3.client.default.access_key; elasticsearch-keystore add -xf s3.client.default.secret_key < /mnt/secure-settings/s3.client.default.secret_key; cp /usr/share/elasticsearch/config/elasticsearch.keystore /keystore/elasticsearch.keystore"
            ],
            "volumeMounts": [
              {"mountPath": "/mnt/secure-settings", "name": "es-secure-settings", "readOnly": true},
              {"mountPath": "/keystore", "name": "keystore-setup"}
            ]
          }
        ],
        "containers": [
          {
            "name": "elasticsearch",
            "volumeMounts": [
              {"mountPath": "/usr/share/elasticsearch/config/elasticsearch.keystore", "name": "keystore-setup", "subPath": "elasticsearch.keystore"}
            ]
          }
        ],
        "volumes": [
          {"name": "keystore-setup", "emptyDir": {}},
          {"name": "es-secure-settings", "secret": {"secretName": "es-secure-settings"}}
        ]
      }
    }
  }
}' 2>&1

# Patch the StatefulSet: remove keystore-setup volumeMount from main container, keep init container for future use but fix approach
kubectl patch statefulset es-cluster -n elasticsearch --type json -p '[
  {
    "op": "remove",
    "path": "/spec/template/spec/containers/0/volumeMounts/6"
  }
]' 2>&1

